// Place global declarations here.
clock globalTime;

//R2 =  
clock R2;
const int R2Init = 100;
const int R2Levels = 100;

//R0 =  
clock R0;
const int R0Init = 100;
const int R0Levels = 100;

//R1 =  
clock R1;
const int R1Init = 100;
const int R1Levels = 100;

//R3 = ERK
clock R3;
const int R3Init = 0;
const int R3Levels = 100;

//R4 = FZD
clock R4;
const int R4Init = 0;
const int R4Levels = 100;

//R5 = FZD I
clock R5;
const int R5Init = 0;
const int R5Levels = 100;

//R6 = IL-1B
clock R6;
const int R6Init = 100;
const int R6Levels = 100;

//R7 = IL-1B R
clock R7;
const int R7Init = 0;
const int R7Levels = 100;

//R8 = IL-1B R I
clock R8;
const int R8Init = 0;
const int R8Levels = 100;

//R9 = JNK1
clock R9;
const int R9Init = 0;
const int R9Levels = 100;

//R10 = Wnt
clock R10;
const int R10Init = 100;
const int R10Levels = 100;

//R11 = p38
clock R11;
const int R11Init = 0;
const int R11Levels = 100;

//Reaction R8 (IL-1B R I) --| R7 (IL-1B R)
const double k_R8_R7 = 0.024;

//Reaction R4 (FZD) --> R3 (ERK)
const double k_R4_R3 = 2.5E-5;

//Reaction R5 (FZD I) --| R4 (FZD)
const double k_R5_R4 = 0.024;

//Reaction R7 (IL-1B R) --> R3 (ERK)
const double k_R7_R3 = 1.0E-4;

//Reaction R10 (Wnt) --> R4 (FZD)
const double k_R10_R4 = 2.0E-4;

//Reaction R0 ( ) --| R9 (JNK1)
const double k_R0_R9 = 2.9999999999999997E-6;

//Reaction R7 (IL-1B R) --> R11 (p38)
const double k_R7_R11 = 1.5E-4;

//Reaction R2 ( ) --| R3 (ERK)
const double k_R2_R3 = 2.9999999999999997E-6;

//Reaction R7 (IL-1B R) --> R9 (JNK1)
const double k_R7_R9 = 8.999999999999999E-5;

//Reaction R4 (FZD) --> R5 (FZD I)
const double k_R4_R5 = 0.003;

//Reaction R7 (IL-1B R) --> R8 (IL-1B R I)
const double k_R7_R8 = 0.002;

//Reaction R6 (IL-1B) --> R7 (IL-1B R)
const double k_R6_R7 = 2.0E-4;

//Reaction R1 ( ) --| R11 (p38)
const double k_R1_R11 = 5.0E-6;

template.declaration:
double rateR2() {
	return 0;
}

double boundedRateR2() {
	return 0;
}

double rateR0() {
	return 0;
}

double boundedRateR0() {
	return 0;
}

double rateR1() {
	return 0;
}

double boundedRateR1() {
	return 0;
}

double rateR3() {
	double R4_R3_r = k_R4_R3 * (R3Levels - R3) * R4;
	double R7_R3_r = k_R7_R3 * (R3Levels - R3) * R7;
	double R2_R3_r = k_R2_R3 * R3 * R2;
	return R4_R3_r + R7_R3_r - R2_R3_r;
}

double boundedRateR3() {
	double r = rateR3();
	if (R3 + r > R3Levels) {
		return R3Levels - R3;
	} else if (R3 + r < 0) {
		return -R3;
	}
	return r;
}

double rateR4() {
	double R5_R4_r = k_R5_R4 * R5;
	double R10_R4_r = k_R10_R4 * (R4Levels - R4) * R10;
	return  - R5_R4_r + R10_R4_r;
}

double boundedRateR4() {
	double r = rateR4();
	if (R4 + r > R4Levels) {
		return R4Levels - R4;
	} else if (R4 + r < 0) {
		return -R4;
	}
	return r;
}

double rateR5() {
	double R4_R5_r = k_R4_R5 * R4;
	return R4_R5_r;
}

double boundedRateR5() {
	double r = rateR5();
	if (R5 + r > R5Levels) {
		return R5Levels - R5;
	} else if (R5 + r < 0) {
		return -R5;
	}
	return r;
}

double rateR6() {
	return 0;
}

double boundedRateR6() {
	return 0;
}

double rateR7() {
	double R8_R7_r = k_R8_R7 * R8;
	double R6_R7_r = k_R6_R7 * (R7Levels - R7) * R6;
	return  - R8_R7_r + R6_R7_r;
}

double boundedRateR7() {
	double r = rateR7();
	if (R7 + r > R7Levels) {
		return R7Levels - R7;
	} else if (R7 + r < 0) {
		return -R7;
	}
	return r;
}

double rateR8() {
	double R7_R8_r = k_R7_R8 * R7;
	return R7_R8_r;
}

double boundedRateR8() {
	double r = rateR8();
	if (R8 + r > R8Levels) {
		return R8Levels - R8;
	} else if (R8 + r < 0) {
		return -R8;
	}
	return r;
}

double rateR9() {
	double R0_R9_r = k_R0_R9 * R9 * R0;
	double R7_R9_r = k_R7_R9 * (R9Levels - R9) * R7;
	return  - R0_R9_r + R7_R9_r;
}

double boundedRateR9() {
	double r = rateR9();
	if (R9 + r > R9Levels) {
		return R9Levels - R9;
	} else if (R9 + r < 0) {
		return -R9;
	}
	return r;
}

double rateR10() {
	return 0;
}

double boundedRateR10() {
	return 0;
}

double rateR11() {
	double R7_R11_r = k_R7_R11 * (R11Levels - R11) * R7;
	double R1_R11_r = k_R1_R11 * R11 * R1;
	return R7_R11_r - R1_R11_r;
}

double boundedRateR11() {
	double r = rateR11();
	if (R11 + r > R11Levels) {
		return R11Levels - R11;
	} else if (R11 + r < 0) {
		return -R11;
	}
	return r;
}
